#include <stdio.h>
#include <math.h>

#define W 2400
#define H 1800

static double clamp(double x){return x<0?0:x>1?1:x;}

int main(void){
    /* scene params */
    double A=1.3333333,B=1.0;
    double Cx=0.0,Cy=-0.327,Cz=-3.283,R=0.653;
    double h=1.0,ts=0.6667,a=0.267;
    double Lx=0.603,Ly=0.591,Lz=-0.572;
    double ln=sqrt(Lx*Lx+Ly*Ly+Lz*Lz);
    Lx/=ln;Ly/=ln;Lz/=ln;
    double br=0.7765,bg=0.153,bb=0.153;
    double g1=152.0,g2=67.0,shf=0.30;

    FILE*f=fopen("reconstructed.ppm","w");
    fprintf(f,"P3\n%d %d\n255\n",W,H);
    for(int y=0;y<H;y++){
        double pv=(1.0-2.0*(y+0.5)/H)*B;
        for(int x=0;x<W;x++){
            double pu=(2.0*(x+0.5)/W-1.0)*A;
            double dx=pu,dy=pv,dz=-1.0;
            double dn=sqrt(dx*dx+dy*dy+dz*dz);
            dx/=dn;dy/=dn;dz/=dn;
            double r,g,b;
            /* sphere */
            double ocx=-Cx,ocy=-Cy,ocz=-Cz;
            double bq=dx*ocx+dy*ocy+dz*ocz;
            double cq=ocx*ocx+ocy*ocy+ocz*ocz-R*R;
            double disc=bq*bq-cq;
            double tsp=-1.0;
            if(disc>0){double t=-bq-sqrt(disc); if(t>1e-3) tsp=t;}
            if(tsp>0){
                double sx=dx*tsp,sy=dy*tsp,sz=dz*tsp;
                double Nx=(sx-Cx)/R,Ny=(sy-Cy)/R,Nz=(sz-Cz)/R;
                double nl=Nx*Lx+Ny*Ly+Nz*Lz; if(nl<0)nl=0;
                double sh=a+(1-a)*nl;
                r=br*sh;g=bg*sh;b=bb*sh;
            } else if(dy<-1e-6){
                /* plane y=-h */
                double tp=(-h)/dy;
                double hx=dx*tp,hz=dz*tp;
                long ix=(long)floor(hx/ts)+(long)floor(hz/ts);
                double grey=((ix&1L)==0)?g1:g2;
                /* shadow */
                double fx=hx-Cx,fy=-h-Cy,fz=hz-Cz;
                double sb=fx*Lx+fy*Ly+fz*Lz;
                double sc=fx*fx+fy*fy+fz*fz-R*R;
                double sd=sb*sb-sc;
                int sh=0;
                if(sd>0){double t=-sb-sqrt(sd); if(t>1e-3) sh=1;}
                grey*=sh?shf:1.0;
                r=g=b=grey/255.0;
            } else {
                double tk=0.5*(dy+1.0);
                r=(1-tk)+tk*0.5; g=(1-tk)+tk*0.7; b=1.0;
            }
            int ri=(int)(clamp(r)*255.0+0.5);
            int gi=(int)(clamp(g)*255.0+0.5);
            int bi=(int)(clamp(b)*255.0+0.5);
            fprintf(f,"%d %d %d\n",ri,gi,bi);
        }
    }
    fclose(f);
    return 0;
}

