#include <stdio.h>
#include <math.h>

#define W 2400
#define H 1800

typedef struct{double x,y,z;}V;
static V vc(double x,double y,double z){V v={x,y,z};return v;}
static V sub(V a,V b){return vc(a.x-b.x,a.y-b.y,a.z-b.z);}
static V add(V a,V b){return vc(a.x+b.x,a.y+b.y,a.z+b.z);}
static V mul(V a,double s){return vc(a.x*s,a.y*s,a.z*s);}
static double dot(V a,V b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static V norm(V a){double l=sqrt(dot(a,a));return vc(a.x/l,a.y/l,a.z/l);}

static V SC;      /* sphere center */
static double SR; /* sphere radius */
static V L;       /* light dir (normalized) */

/* nearest sphere hit t>tmin, or -1 */
static double sphere_hit(V o,V d){
    V oc=sub(o,SC);
    double a=dot(d,d), b=2*dot(oc,d), c=dot(oc,oc)-SR*SR;
    double disc=b*b-4*a*c;
    if(disc<0) return -1;
    double s=sqrt(disc);
    double t=(-b-s)/(2*a);
    if(t>0.001) return t;
    t=(-b+s)/(2*a);
    if(t>0.001) return t;
    return -1;
}

int main(void){
    double vph=2.0;
    double vpw=(double)W/H*vph;
    double focal=1.0;
    V origin=vc(0,0,0);
    V horiz=vc(vpw,0,0);
    V vert=vc(0,vph,0);
    V ll=sub(sub(sub(origin,mul(horiz,0.5)),mul(vert,0.5)),vc(0,0,focal));
    SC=vc(0,-0.5,-5.0); SR=1.0;
    L=norm(vc(1,1,-1));
    double planeY=-1.5;
    double ambient=0.2;

    FILE*f=fopen("reconstructed.ppm","w");
    fprintf(f,"P3\n%d %d\n255\n",W,H);
    for(int j=0;j<H;j++){
        double v=(double)j/(H-1);
        for(int i=0;i<W;i++){
            double u=(double)i/(W-1);
            V dir=norm(sub(add(add(ll,mul(horiz,u)),mul(vert,1.0-v)),origin));
            V col;
            double ts=sphere_hit(origin,dir);
            double tp=-1;
            if(fabs(dir.y)>1e-4){double t=(planeY-origin.y)/dir.y; if(t>0.001) tp=t;}
            int isobj; double t;
            if(ts>0 && (tp<0 || ts<tp)){isobj=1;t=ts;}
            else if(tp>0){isobj=0;t=tp;}
            else {isobj=-1;t=0;}
            if(isobj<0){
                double tk=0.5*(dir.y+1.0);
                col=add(mul(vc(1,1,1),1-tk),mul(vc(0.5,0.7,1.0),tk));
            } else {
                V p=add(origin,mul(dir,t));
                V n; double alb_r,alb_g,alb_b;
                if(isobj){
                    n=norm(sub(p,SC));
                    alb_r=1.0;alb_g=0.2;alb_b=0.2;
                } else {
                    n=vc(0,1,0);
                    long ck=(long)floor(p.x)+(long)floor(p.z);
                    double g=((ck&1L)==0)?0.9:0.4;
                    alb_r=alb_g=alb_b=g;
                }
                double diff=dot(n,L); if(diff<0)diff=0;
                /* shadow */
                V so=add(p,mul(L,0.001));
                if(sphere_hit(so,L)>0) diff=0;
                double inten=ambient+(1.0-ambient)*diff;
                col=vc(alb_r*inten,alb_g*inten,alb_b*inten);
            }
            double cr=col.x<0?0:col.x>1?1:col.x;
            double cg=col.y<0?0:col.y>1?1:col.y;
            double cb=col.z<0?0:col.z>1?1:col.z;
            fprintf(f,"%d %d %d\n",(int)(cr*255.99),(int)(cg*255.99),(int)(cb*255.99));
        }
    }
    fclose(f);
    return 0;
}

